css:
atom-text-editor {
  background-color: #2b303b;
  color: #c0c5ce;
}
atom-text-editor .wrap-guide {
  background-color: #343d46;
}
atom-text-editor .indent-guide {
  color: #343d46;
}
atom-text-editor .invisible-character {
  color: #343d46;
}
atom-text-editor .gutter {
  background-color: #2b303b;
  color: #c0c5ce;
}
atom-text-editor .gutter .line-number.cursor-line {
  background-color: #4f5b66;
}
atom-text-editor .gutter .line-number.cursor-line-no-selection {
  background-color: #343d46;
  color: #4f5b66;
}
atom-text-editor .gutter .line-number.folded,
atom-text-editor .gutter .line-number:after,
atom-text-editor .fold-marker:after {
  color: #eff1f5;
}
atom-text-editor .invisible {
  color: #c0c5ce;
}
atom-text-editor .cursor {
  color: #eff1f5;
}
atom-text-editor .selection .region {
  background-color: #4f5b66;
}
atom-text-editor .search-results .syntax--marker .region {
  background-color: transparent;
  border: 1px solid #a7adba;
}
atom-text-editor .search-results .syntax--marker.current-result .region {
  border: 1px solid #eff1f5;
}
.syntax--comment {
  font-style: italic;
  color: #65737e;
}
.syntax--keyword {
  color: #b48ead;
}
.syntax--keyword.syntax--control {
  color: #b48ead;
}
.syntax--keyword.syntax--operator {
  color: #c0c5ce;
}
.syntax--keyword.syntax--other.syntax--special-method {
  color: #8fa1b3;
}
.syntax--keyword.syntax--other.syntax--unit {
  color: #d08770;
}
.syntax--storage {
  color: #b48ead;
}
.syntax--constant {
  color: #d08770;
}
.syntax--constant.syntax--character.syntax--escape {
  color: #96b5b4;
}
.syntax--constant.syntax--numeric {
  color: #d08770;
}
.syntax--constant.syntax--other.syntax--color {
  color: #96b5b4;
}
.syntax--constant.syntax--other.syntax--symbol {
  color: #a3be8c;
}
.syntax--variable {
  color: #bf616a;
}
.syntax--variable.syntax--interpolation {
  color: #a9444e;
}
.syntax--variable.syntax--parameter.syntax--function {
  color: #c0c5ce;
}
.syntax--invalid.syntax--illegal {
  background-color: #bf616a;
  color: #2b303b;
}
.syntax--string {
  color: #a3be8c;
}
.syntax--string.syntax--regexp {
  color: #96b5b4;
}
.syntax--string.syntax--regexp .syntax--source.syntax--ruby.syntax--embedded {
  color: #d08770;
}
.syntax--string.syntax--other.syntax--link {
  color: #bf616a;
}
.syntax--punctuation.syntax--definition.syntax--comment {
  font-style: italic;
  color: #65737e;
}
.syntax--punctuation.syntax--definition.syntax--string,
.syntax--punctuation.syntax--definition.syntax--variable,
.syntax--punctuation.syntax--definition.syntax--parameters,
.syntax--punctuation.syntax--definition.syntax--array {
  color: #c0c5ce;
}
.syntax--punctuation.syntax--definition.syntax--heading,
.syntax--punctuation.syntax--definition.syntax--identity {
  color: #8fa1b3;
}
.syntax--punctuation.syntax--definition.syntax--bold {
  color: #ebcb8b;
  font-weight: bold;
}
.syntax--punctuation.syntax--definition.syntax--italic {
  color: #b48ead;
  font-style: italic;
}
.syntax--punctuation.syntax--section.syntax--embedded {
  color: #a9444e;
}
.syntax--support.syntax--class {
  color: #ebcb8b;
}
.syntax--support.syntax--function {
  color: #96b5b4;
}
.syntax--support.syntax--function.syntax--any-method {
  color: #8fa1b3;
}
.syntax--entity.syntax--name.syntax--function {
  color: #8fa1b3;
}
.syntax--entity.syntax--name.syntax--type {
  color: #d08770;
  text-decoration: underline;
}
.syntax--entity.syntax--other.syntax--inherited-class {
  color: #a3be8c;
}
.syntax--entity.syntax--name.syntax--class,
.syntax--entity.syntax--name.syntax--type.syntax--class {
  color: #ebcb8b;
}
.syntax--entity.syntax--name.syntax--section {
  color: #8fa1b3;
}
.syntax--entity.syntax--name.syntax--tag {
  color: #bf616a;
  text-decoration: underline;
}
.syntax--entity.syntax--other.syntax--attribute-name {
  color: #d08770;
}
.syntax--entity.syntax--other.syntax--attribute-name.syntax--id {
  color: #8fa1b3;
}
.syntax--meta.syntax--class {
  color: #eff1f5;
}
.syntax--meta.syntax--link {
  color: #d08770;
}
.syntax--meta.syntax--require {
  color: #8fa1b3;
}
.syntax--meta.syntax--selector {
  color: #b48ead;
}
.syntax--meta.syntax--separator {
  background-color: #4f5b66;
  color: #c0c5ce;
}
.syntax--none {
  color: #c0c5ce;
}
.syntax--markup.syntax--bold {
  font-weight: bold;
  color: #ebcb8b;
}
.syntax--markup.syntax--changed {
  color: #b48ead;
}
.syntax--markup.syntax--deleted {
  color: #bf616a;
}
.syntax--markup.syntax--italic {
  color: #b48ead;
  font-style: italic;
}
.syntax--markup.syntax--heading .syntax--punctuation.syntax--definition.syntax--heading {
  color: #8fa1b3;
}
.syntax--markup.syntax--inserted {
  color: #a3be8c;
}
.syntax--markup.syntax--list {
  color: #bf616a;
}
.syntax--markup.syntax--quote {
  color: #d08770;
}
.syntax--markup.syntax--raw.syntax--inline {
  color: #a3be8c;
}
.syntax--source.syntax--gfm .syntax--markup {
  -webkit-font-smoothing: auto;
}
.syntax--source.syntax--gfm .syntax--markup.syntax--heading {
  color: #a3be8c;
}
atom-text-editor[mini] .scroll-view {
  padding-left: 1px;
}
.bracket-matcher .region {
  border-color: #a3be8c;
}
.syntax--java.syntax--storage.syntax--import,
.syntax--java.syntax--storage.syntax--package {
  color: #c0c5ce;
}
